const ROUTER = '0xd9e1cE17f2641f24aE83637ab66a2cca9C378B9F';
const WETH = '0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2';

const [, directOut] = await client.readContract({
  address: ROUTER, abi: ROUTER_ABI, functionName: 'getAmountsOut',
  args: [amountIn, [tokenIn, tokenOut]]
});
const [, , bridgedOut] = await client.readContract({
  address: ROUTER, abi: ROUTER_ABI, functionName: 'getAmountsOut',
  args: [amountIn, [tokenIn, WETH, tokenOut]]
});
const path = directOut > bridgedOut ? [tokenIn, tokenOut] : [tokenIn, WETH, tokenOut];
const quote = directOut > bridgedOut ? directOut : bridgedOut;
const amountOutMin = (quote * 9900n) / 10000n; // 1% slippage

await wallet.writeContract({ address: tokenIn, abi: ERC20_ABI, functionName: 'approve', args: [ROUTER, amountIn] });
await wallet.writeContract({
  address: ROUTER, abi: ROUTER_ABI, functionName: 'swapExactTokensForTokens',
  args: [amountIn, amountOutMin, path, agent, BigInt(Math.floor(Date.now()/1000) + 300)]
});
